pragma solidity ^0.4.9;

contract TownCrier {
    struct Request {
        address requester;
        uint fee;
        address callbackAddr;
        bytes4 callbackFID;
        bytes32 paramsHash;
    }

    event Upgrade(address newAddr);
    event Reset(uint gas_price, uint min_fee, uint cancellation_fee);
    event RequestInfo(
        uint64 id,
        uint8 requestType,
        address requester,
        uint fee,
        address callbackAddr,
        bytes32 paramsHash,
        uint timestamp,
        bytes32[] requestData
    );
    event DeliverInfo(
        uint64 requestId,
        uint fee,
        uint gasPrice,
        uint gasLeft,
        uint callbackGas,
        bytes32 paramsHash,
        uint64 error,
        bytes32 respData
    );
    event Cancel(
        uint64 requestId,
        address canceller,
        address requester,
        uint fee,
        int flag
    );

    address public constant SGX_ADDRESS =
        0x18513702cCd928F2A3eb63d900aDf03c9cc81593;

    uint public GAS_PRICE = 5 * 10 ** 10;
    uint public MIN_FEE = 30000 * GAS_PRICE;
    uint public CANCELLATION_FEE = 25000 * GAS_PRICE;

    uint public constant CANCELLED_FEE_FLAG = 1;
    uint public constant DELIVERED_FEE_FLAG = 0;
    int public constant FAIL_FLAG = -2 ** 250;
    int public constant SUCCESS_FLAG = 1;

    bool public killswitch;

    bool public externalCallFlag;

    uint64 public requestCnt;
    uint64 public unrespondedCnt;
    Request[2 ** 64] public requests;

    int public newVersion = 0;

    function() {}

    function TownCrier() public {
        requestCnt = 1;
        requests[0].requester = msg.sender;
        killswitch = false;
        unrespondedCnt = 0;
        externalCallFlag = false;
    }

    function upgrade(address newAddr) {
        if (msg.sender == requests[0].requester && unrespondedCnt == 0) {
            newVersion = -int(newAddr);
            killswitch = true;
            Upgrade(newAddr);
        }
    }

    function reset(uint price, uint minGas, uint cancellationGas) public {
        if (msg.sender == requests[0].requester && unrespondedCnt == 0) {
            GAS_PRICE = price;
            MIN_FEE = price * minGas;
            CANCELLATION_FEE = price * cancellationGas;
            Reset(GAS_PRICE, MIN_FEE, CANCELLATION_FEE);
        }
    }

    function suspend() public {
        if (msg.sender == requests[0].requester) {
            killswitch = true;
        }
    }

    function restart() public {
        if (msg.sender == requests[0].requester && newVersion == 0) {
            killswitch = false;
        }
    }

    function withdraw() public {
        if (msg.sender == requests[0].requester && unrespondedCnt == 0) {
            if (!requests[0].requester.call.value(this.balance)()) {
                throw;
            }
        }
    }

    function request(
        uint8 requestType,
        address callbackAddr,
        bytes4 callbackFID,
        uint timestamp,
        bytes32[] requestData
    ) public payable returns (int) {
        if (externalCallFlag) {
            throw;
        }

        if (killswitch) {
            externalCallFlag = true;
            if (!msg.sender.call.value(msg.value)()) {
                throw;
            }
            externalCallFlag = false;
            return newVersion;
        }

        if (msg.value < MIN_FEE) {
            externalCallFlag = true;

            if (!msg.sender.call.value(msg.value)()) {
                throw;
            }
            externalCallFlag = false;
            return FAIL_FLAG;
        } else {
            uint64 requestId = requestCnt;
            requestCnt++;
            unrespondedCnt++;

            bytes32 paramsHash = sha3(requestType, requestData);
            requests[requestId].requester = msg.sender;
            requests[requestId].fee = msg.value;
            requests[requestId].callbackAddr = callbackAddr;
            requests[requestId].callbackFID = callbackFID;
            requests[requestId].paramsHash = paramsHash;

            RequestInfo(
                requestId,
                requestType,
                msg.sender,
                msg.value,
                callbackAddr,
                paramsHash,
                timestamp,
                requestData
            );
            return requestId;
        }
    }

    function deliver(
        uint64 requestId,
        bytes32 paramsHash,
        uint64 error,
        bytes32 respData
    ) public {
        if (
            msg.sender != SGX_ADDRESS ||
            requestId <= 0 ||
            requests[requestId].requester == 0 ||
            requests[requestId].fee == DELIVERED_FEE_FLAG
        ) {
            return;
        }

        uint fee = requests[requestId].fee;
        if (requests[requestId].paramsHash != paramsHash) {
            return;
        } else if (fee == CANCELLED_FEE_FLAG) {
            SGX_ADDRESS.send(CANCELLATION_FEE);
            requests[requestId].fee = DELIVERED_FEE_FLAG;
            unrespondedCnt--;
            return;
        }

        requests[requestId].fee = DELIVERED_FEE_FLAG;
        unrespondedCnt--;

        if (error < 2) {
            SGX_ADDRESS.send(fee);
        } else {
            externalCallFlag = true;

            requests[requestId].requester.call.gas(2300).value(fee)();
            externalCallFlag = false;
        }

        uint callbackGas = (fee - MIN_FEE) / tx.gasprice;
        DeliverInfo(
            requestId,
            fee,
            tx.gasprice,
            msg.gas,
            callbackGas,
            paramsHash,
            error,
            respData
        );
        if (callbackGas > msg.gas - 5000) {
            callbackGas = msg.gas - 5000;
        }

        externalCallFlag = true;

        requests[requestId].callbackAddr.call.gas(callbackGas)(
            requests[requestId].callbackFID,
            requestId,
            error,
            respData
        );
        externalCallFlag = false;
    }

    function cancel(uint64 requestId) public returns (int) {
        if (externalCallFlag) {
            throw;
        }

        if (killswitch) {
            return 0;
        }

        uint fee = requests[requestId].fee;
        if (
            requests[requestId].requester == msg.sender &&
            fee >= CANCELLATION_FEE
        ) {
            requests[requestId].fee = CANCELLED_FEE_FLAG;
            externalCallFlag = true;
            if (!msg.sender.call.value(fee - CANCELLATION_FEE)()) {
                throw;
            }
            externalCallFlag = false;
            Cancel(
                requestId,
                msg.sender,
                requests[requestId].requester,
                requests[requestId].fee,
                1
            );
            return SUCCESS_FLAG;
        } else {
            Cancel(
                requestId,
                msg.sender,
                requests[requestId].requester,
                fee,
                -1
            );
            return FAIL_FLAG;
        }
    }
}

Here are nine common vulnerabilities:

ID: Access Control
Description: Improper restriction of function access, allowing unauthorized users to execute critical functions.

ID: Arithmetic
Description: Missing or incorrect integer overflow/underflow checks, leading to unexpected values.

ID: Bad Randomness
Description: Use of predictable values for randomness, which attackers can manipulate.

ID: Denial Of Service
Description: Malicious actions that consume excessive gas or exploit fallback behavior to block contract functionality.

ID: Front Running
Description: Exploiting transaction order to manipulate outcomes before others.

ID: Reentrancy
Description: Recursive calls into the same contract before the initial function completes, leading to unexpected state changes.

ID: Short Addresses
Description: Failure to validate input lengths, allowing crafted shorter inputs to corrupt parameters.

ID: Time Manipulation
Description: Dependence on block timestamps that miners can influence.

ID: Unchecked Low Level Calls
Description: Calls to low-level functions like 'call()' without checking return values, which can silently fail.


Here is a complete example of the expected output format, followed by additional examples showing how individual vulnerabilities may be identified and explained:

- Example 1
Input:
```
function initContract() public {
	owner = msg.sender;
}
```
Output:
Access Control: Present
Explanation: The contract's initialization function sets the caller as the owner but is not part of the constructor. It lacks access restrictions and does not track whether it has already been called. As a result, any user can invoke the function and assign ownership to themselves, potentially leading to unauthorized access to privileged functionality.

Arithmetic: Absent
Explanation: The snippet does not contain arithmetic operations suggesting overflow or underflow issues.

Bad Randomness: Absent
Explanation: The snippet does not use any randomness source.

Denial Of Service: Absent
Explanation: The snippet does not show an external interaction or blocking pattern that would cause denial of service.

Front Running: Absent
Explanation: The snippet does not expose a transaction-order-dependent action or secret that could be exploited by observing pending transactions.

Reentrancy: Absent
Explanation: The snippet does not perform an external call that could allow reentrant execution.

Short Addresses: Absent
Explanation: The snippet does not process external address or calldata inputs in a way that suggests a short address issue.

Time Manipulation: Absent
Explanation: The snippet does not depend on block timestamps or time-related block properties.

Unchecked Low Level Calls: Absent
Explanation: The snippet does not use low-level calls such as call(), delegatecall(), or send().


